// Generated by Claude Opus 4.6

import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import React from 'react';

import TerminalTools from '@/components/TerminalTools';

describe('TerminalTools', () => {
  const mockOnToggleExpand = jest.fn();

  afterEach(() => {
    jest.clearAllMocks();
  });

  test('should render Expand button when not expanded', () => {
    render(<TerminalTools isExpanded={false} onToggleExpand={mockOnToggleExpand} />);

    expect(screen.getByText('Expand')).toBeTruthy();
    expect(screen.queryByText('Compress')).toBeNull();
  });

  test('should render Compress button when expanded', () => {
    render(<TerminalTools isExpanded={true} onToggleExpand={mockOnToggleExpand} />);

    expect(screen.getByText('Compress')).toBeTruthy();
    expect(screen.queryByText('Expand')).toBeNull();
  });

  test('should call onToggleExpand when Expand button is clicked', async () => {
    const user = userEvent.setup();
    render(<TerminalTools isExpanded={false} onToggleExpand={mockOnToggleExpand} />);

    const expandButton = screen.getByRole('button', { name: 'Expand' });
    await user.click(expandButton);

    expect(mockOnToggleExpand).toHaveBeenCalledTimes(1);
  });

  test('should call onToggleExpand when Compress button is clicked', async () => {
    const user = userEvent.setup();
    render(<TerminalTools isExpanded={true} onToggleExpand={mockOnToggleExpand} />);

    const compressButton = screen.getByRole('button', { name: 'Compress' });
    await user.click(compressButton);

    expect(mockOnToggleExpand).toHaveBeenCalledTimes(1);
  });

  test('should switch from Expand to Compress when re-rendered', () => {
    const { rerender } = render(
      <TerminalTools isExpanded={false} onToggleExpand={mockOnToggleExpand} />,
    );

    expect(screen.getByText('Expand')).toBeTruthy();

    rerender(<TerminalTools isExpanded={true} onToggleExpand={mockOnToggleExpand} />);

    expect(screen.getByText('Compress')).toBeTruthy();
    expect(screen.queryByText('Expand')).toBeNull();
  });

  test('should switch from Compress to Expand when re-rendered', () => {
    const { rerender } = render(
      <TerminalTools isExpanded={true} onToggleExpand={mockOnToggleExpand} />,
    );

    expect(screen.getByText('Compress')).toBeTruthy();

    rerender(<TerminalTools isExpanded={false} onToggleExpand={mockOnToggleExpand} />);

    expect(screen.getByText('Expand')).toBeTruthy();
    expect(screen.queryByText('Compress')).toBeNull();
  });

  test('should render a single button element', () => {
    render(<TerminalTools isExpanded={false} onToggleExpand={mockOnToggleExpand} />);

    const buttons = screen.getAllByRole('button');
    expect(buttons.length).toBe(1);
  });
});
